+                var i: usize = 0;
+                while (i < self.response_queue.items.len) : (i += 1) {
+                    const entry = self.response_queue.items[i];
+                    if (entry.id == id) {
+                        const response = entry.payload;
+                        _ = self.response_queue.swapRemove(i);
